import React, { useState } from "react";
import UploadImage from "./UploadImage";
import { ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

function App() {
  const [darkMode, setDarkMode] = useState(false);

  // Toggle dark/light mode
  const toggleDarkMode = () => {
    setDarkMode((prevMode) => !prevMode);
  };

  return (
    <div className={`${darkMode ? "dark" : ""} min-h-screen flex flex-col bg-gray-50 dark:bg-gray-900 font-sans`}>
      {/* Header / Hero Section */}
      <header className="relative w-full overflow-hidden bg-gradient-to-r from-blue-600 via-blue-700 to-blue-800 text-white shadow-md">
        {/* Dark Mode Toggle */}
        <div className="absolute top-4 right-4">
          <button
            onClick={toggleDarkMode}
            className="px-3 py-1 bg-white text-blue-800 rounded-md shadow hover:bg-blue-100 transition"
          >
            {darkMode ? "Light Mode" : "Dark Mode"}
          </button>
        </div>

        {/* Inline Background Pattern */}
        <div
          style={{
            backgroundImage: `url(${process.env.PUBLIC_URL}/assets/pattern.svg)`,
          }}
          className="absolute inset-0 opacity-20 pointer-events-none bg-cover bg-center"
        />

        <div className="max-w-6xl mx-auto px-6 py-12 text-center relative z-10">
          <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight drop-shadow-sm">
            Medical Images AI
          </h1>
          <p className="mt-2 text-lg md:text-xl font-medium">
            Harness AI to assist in medical imaging analysis
          </p>
          <a
            href="#main-content"
            className="inline-block mt-6 px-8 py-3 bg-white text-blue-700 font-semibold rounded-md shadow hover:shadow-lg hover:bg-blue-50 transition-all"
          >
            Get Started
          </a>
        </div>
      </header>

      {/* Main Content Container */}
      <main id="main-content" className="flex-1 w-full max-w-6xl mx-auto px-4 mt-8 mb-8">
        {/* Multi-Step Wizard Indicator */}
        <div className="flex justify-center space-x-4 mb-6">
          <div className="px-4 py-2 bg-blue-600 text-white rounded-full shadow">
            Step 1: Upload
          </div>
          <div className="px-4 py-2 bg-gray-300 text-gray-700 dark:bg-gray-700 dark:text-gray-300 rounded-full shadow">
            Step 2: Analyze
          </div>
          <div className="px-4 py-2 bg-gray-300 text-gray-700 dark:bg-gray-700 dark:text-gray-300 rounded-full shadow">
            Step 3: Results
          </div>
        </div>

        {/* Upload & Analysis Card */}
        <section className="bg-white dark:bg-gray-800 rounded-lg shadow-md p-6 mx-auto hover:shadow-lg transition-shadow duration-200">
          <UploadImage />
        </section>

        {/* Disclaimer Section */}
        <section className="mt-6 p-4 bg-yellow-100 dark:bg-yellow-200 border-l-4 border-yellow-400 rounded-md text-yellow-800 dark:text-yellow-900">
          <p className="text-sm leading-relaxed">
            <strong>Disclaimer:</strong> This AI tool is designed to <em>assist</em> with medical imaging analysis,
            but it does <em>not</em> replace the expertise of a certified medical professional.
            Always consult a qualified practitioner for final interpretations and decisions.
            This system is not FDA-approved or CE-marked.
          </p>
        </section>
      </main>

      {/* Footer */}
      <footer className="w-full py-6 bg-white dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700">
        <div className="max-w-6xl mx-auto px-4 text-center text-gray-500 dark:text-gray-400 text-sm">
          <p>&copy; 2025 Medical Images AI. All rights reserved.</p>
          <p className="mt-1">
            <a
              href="#"
              className="text-blue-600 dark:text-blue-400 hover:underline transition-colors"
            >
              Privacy Policy
            </a>{" "}
            |{" "}
            <a
              href="#"
              className="text-blue-600 dark:text-blue-400 hover:underline transition-colors"
            >
              Terms of Service
            </a>
          </p>
        </div>
      </footer>

      {/* Toast Notifications */}
      <ToastContainer
        position="bottom-right"
        autoClose={3000}
        hideProgressBar={false}
        newestOnTop={false}
        closeOnClick
        pauseOnFocusLoss
        draggable
        pauseOnHover
      />
    </div>
  );
}

export default App;
